/**
 * LoginGate — 인증 게이트 공통 컴포넌트
 *
 * - busy: 풀스크린 스피너 표시
 * - user === null: 로그인 유도 화면 표시
 * - user !== null: children 렌더링
 *
 * 라우터 의존성 없음 (wouter / react-router-dom 둘 다 import 안 함).
 */
import React from "react";
import { motion } from "framer-motion";
import { useAuthState } from "@hh/shared";

export interface LoginGateProps {
  /** 앱 이름, e.g. "POT SPLIT" */
  appName: string;
  /** 부제목, e.g. "팟 분배 계산 퀴즈" */
  subtitle: string;
  /** MIMIC 로고 이미지 src */
  logoSrc: string;
  /** 배경 비디오 src (없으면 dark gradient) */
  bgVideoSrc?: string;
  children: React.ReactNode;
}

export function LoginGate({
  appName,
  subtitle,
  logoSrc,
  bgVideoSrc,
  children,
}: LoginGateProps) {
  const { user, busy } = useAuthState();

  if (busy) {
    return (
      <div
        style={{
          height: "100dvh",
          background: "#ffffff",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <div className="w-8 h-8 border-2 border-gray-200 border-t-[#E5343A] rounded-full animate-spin" />
      </div>
    );
  }

  if (!user) {
    const hasVideo = Boolean(bgVideoSrc);

    const overlayStyle: React.CSSProperties = hasVideo
      ? {
          background:
            "linear-gradient(180deg, rgba(255,255,255,0.85) 0%, rgba(255,255,255,0.6) 40%, rgba(255,255,255,0.85) 100%)",
        }
      : {
          background:
            "linear-gradient(180deg, rgba(10,10,26,0.3) 0%, rgba(10,10,26,0.1) 50%, rgba(10,10,26,0.3) 100%)",
        };

    const titleColor = hasVideo ? "#1a1a2e" : "#FFFCF3";
    const subtitleColor = hasVideo ? "rgba(0,0,0,0.45)" : "rgba(255,252,243,0.6)";
    const guideBoxBg = hasVideo ? "rgba(0,0,0,0.04)" : "rgba(255,255,255,0.05)";
    const guideBoxBorder = hasVideo
      ? "1px solid rgba(0,0,0,0.08)"
      : "1px solid rgba(255,255,255,0.1)";
    const guideTextColor = hasVideo ? "#1a1a2e" : "#FFFCF3";
    const guideSubColor = hasVideo ? "rgba(0,0,0,0.4)" : "rgba(255,252,243,0.5)";
    const footerColor = hasVideo ? "rgba(0,0,0,0.2)" : "rgba(255,252,243,0.2)";

    return (
      <div
        style={{
          height: "100dvh",
          background: "#ffffff",
          display: "flex",
          justifyContent: "center",
        }}
      >
        <div
          className="relative flex flex-col w-full overflow-hidden"
          style={{ maxWidth: 430, height: "100%" }}
        >
          {/* Background */}
          {hasVideo ? (
            <video
              autoPlay
              muted
              playsInline
              loop
              className="absolute inset-0 w-full h-full object-cover"
              style={{ zIndex: 0, transform: "scaleX(-1)" }}
              src={bgVideoSrc}
            />
          ) : (
            <div
              className="absolute inset-0"
              style={{
                zIndex: 0,
                background:
                  "linear-gradient(160deg, #0a0a1a 0%, #1a0a2e 50%, #0a0a1a 100%)",
              }}
            />
          )}

          {/* Overlay */}
          <div
            className="absolute inset-0 z-[1]"
            style={overlayStyle}
          />

          {/* Content */}
          <div className="relative z-10 flex-1 flex flex-col items-center justify-center px-8">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
              className="flex flex-col items-center"
            >
              <img
                src={logoSrc}
                alt="MIMIC"
                style={{ height: 36, marginBottom: 8 }}
              />
              <h1
                className="font-black tracking-tight"
                style={{
                  fontSize: 32,
                  color: titleColor,
                  marginBottom: 8,
                }}
              >
                {appName}
              </h1>
              <p
                className="text-center font-medium"
                style={{
                  fontSize: 14,
                  color: subtitleColor,
                  lineHeight: 1.5,
                  marginBottom: 40,
                }}
              >
                {subtitle}
              </p>

              {/* 로그인 안내 박스 */}
              <div
                className="flex flex-col items-center gap-3 rounded-2xl px-6 py-5 text-center"
                style={{
                  background: guideBoxBg,
                  border: guideBoxBorder,
                  width: "100%",
                  maxWidth: 300,
                }}
              >
                {/* 아이콘 */}
                <div
                  className="w-10 h-10 rounded-full flex items-center justify-center"
                  style={{ background: "#E5343A" }}
                >
                  <svg
                    width="18"
                    height="18"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="white"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
                    <circle cx="12" cy="7" r="4" />
                  </svg>
                </div>

                {/* 안내 문구 */}
                <p
                  style={{
                    fontSize: 14,
                    color: guideTextColor,
                    fontWeight: 600,
                    lineHeight: 1.5,
                  }}
                >
                  화면 상단의 로그인 버튼을
                  <br />
                  눌러 시작하세요
                </p>
                <p
                  style={{
                    fontSize: 11,
                    color: guideSubColor,
                    lineHeight: 1.6,
                  }}
                >
                  MIMIC PLAYLAB 계정 하나로
                  <br />
                  모든 앱을 이용할 수 있습니다
                </p>
              </div>
            </motion.div>
          </div>

          {/* Footer */}
          <div
            className="relative z-10 text-center pb-8"
            style={{ fontSize: 10, color: footerColor }}
          >
            © MIMIC {appName}
          </div>
        </div>
      </div>
    );
  }

  return <>{children}</>;
}
